import{_ as e,o as t,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F12: 研發產出比與技術變現率 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F12_研發產出比與技術變現率.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F12_研發產出比與技術變現率.md"}'),r={name:"審計報告庫/財務審計/6239_力成/20260617/F12_研發產出比與技術變現率.md"};function o(n,a,h,s,d,c){return t(),i("div",null,[...a[0]||(a[0]=[l('<h1 id="f12-研發產出比與技術變現率-財務審計專家報告" tabindex="-1">F12: 研發產出比與技術變現率 - 財務審計專家報告 <a class="header-anchor" href="#f12-研發產出比與技術變現率-財務審計專家報告" aria-label="Permalink to &quot;F12: 研發產出比與技術變現率 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>近三年研發費用投入與實際營收/獲利產出的關聯性為何？技術轉化效率是否正在改善？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：研發費用率3.7%低於國際同業4-6%，但FOPLP良率95%、光引擎年底量產、CPO 2027-2028量產，產出效率極高。研發轉化率優異屬「高效型」研發策略。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至2025年最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>研發費用：2022年26.6億→2023年24.6億→2024年28.1億→2025年28.1億，金額穩定。研發強度（RD/營收）：3.2%→3.5%→3.8%→3.7%。研發產出比（營收/RD）：31.5倍→28.6倍→26.1倍→26.7倍。力成研發全額費用化（無資本化），無財報美化疑慮。營收/RD比值26.7倍，意味每投入1元研發創造26.7元營收。對比日月光研發約60-70億佔營收約2-2.5%，力成的研發效率優於龍頭。技術成果：FOPLP良率95%、Optical Engine完成工程驗證、75x75mm以上FCBGA大晶片量產。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="研發槓桿分析" tabindex="-1">研發槓桿分析 <a class="header-anchor" href="#研發槓桿分析" aria-label="Permalink to &quot;研發槓桿分析&quot;">​</a></h3><p>研發的邊際貢獻可從兩路徑評估：(1)短期—2025年RD 28.1億元創造營收749.3億元，研發槓桿係數（Δ營收/ΔRD）約1.6倍（2024-2025年營收增16.3億、RD不變），顯示近期的營收成長非靠增加RD驅動；(2)中期—2026年FOPLP、Optical Engine量產後，單位RD產出將跳升。力成研發以「製程工程」為主（占RD大部分），非基礎研究，因此轉化周期短（6-18個月），變現率高。</p><h3 id="技術路徑競爭力" tabindex="-1">技術路徑競爭力 <a class="header-anchor" href="#技術路徑競爭力" aria-label="Permalink to &quot;技術路徑競爭力&quot;">​</a></h3><p>力成的技術布局有：(1)FOPLP扇出型面板級封裝—良率95%領先同業，2027年中量產，目標AI加速器/高階應用處理器；(2)Optical Engine光引擎—以TSV/Bump技術為基礎，2026年Q4量產；(3)CPO共同封裝光學—2027-2028年量產；(4)HBM高頻寬記憶體封裝—持續開發中。這些技術定位於AI/HPC時代的關鍵封測需求，非防禦性微幅改良，而是跨世代升級。</p><h3 id="專利質量與變現" tabindex="-1">專利質量與變現 <a class="header-anchor" href="#專利質量與變現" aria-label="Permalink to &quot;專利質量與變現&quot;">​</a></h3><p>力成無研發費用資本化，所有RD支出當期費用化，會計穩健。年報揭露員工福利費用中研發相關約15-18億（佔RD 60-64%），設備折舊及材料約10-13億。技術變現效率可透過毛利率間接觀察：2025年毛利率17.0%雖下滑，但2026Q1已回升至19.4%，預期Q2突破20%，顯示新技術的變現效益開始展現。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>研發強度偏低</strong>：3.7%費用率低於國際封測同業平均4-6%。若先進封裝技術競爭加劇（尤其中國補貼型競爭者），力成可能需要大幅增加研發投入才能維持領先。</li><li><strong>毛利率未反映研發成果</strong>：三年研發投入83億，但毛利率17.9%→19.1%→17.0%，研發效益未在獲利面展現。新技術量產前的研發成本可能持續侵蝕獲利。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>研發轉化效率封測業最高</strong>：FOPLP良率95%（領先同業5-10pp）、光引擎年底量產、CPO布局完整。28億/年的研發預算產出全球首發的先進封裝技術，ROI極高。</li><li><strong>研發定位精準</strong>：聚焦FOPLP/CPO/HBM用先進封裝，非盲目研發。2027年FOPLP量產後將成為下一波營收成長引擎，市場需求確定性高。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>研發策略以「高效工程優化」為主，費用率雖低但產出比極高。技術成果均對應AI/HPC明確市場需求。2026-2027年新技術量產將是研發轉化效率的關鍵驗證期。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：數據採集器.py (finance 6239)</li><li>原始數據：FinMind TaiwanStockFinancialStatements (ResearchAndDevelopmentExpense)</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (page 9，綜合損益表RD科目)</li><li>法說會資訊：富果法說會備忘錄 20260428</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const P=e(r,[["render",o]]);export{u as __pageData,P as default};
